        credentials: "\u0411\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e \u043f\u043e\u0434\u043a\u043b\u044e\u0447\u0430\u0439\u0442\u0435\u0441\u044c \u043a \u0441\u0435\u0440\u0432\u0438\u0441\u0430\u043c. \u0423\u0437\u043d\u0430\u0439\u0442\u0435 \u043e \u0437\u0430\u0448\u0438\u0444\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u043c \u0445\u0440\u0430\u043d\u0438\u043b\u0438\u0449\u0435 \u0438 \u043e \u0442\u043e\u043c, \u043a\u0430\u043a \u0432\u0430\u0448\u0438 \u0434\u0430\u043d\u043d\u044b\u0435 \u043e\u0441\u0442\u0430\u044e\u0442\u0441\u044f \u0432 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e\u0441\u0442\u0438.",
        "agents-prompts": "\u0421\u043e\u0437\u0434\u0430\u0432\u0430\u0439\u0442\u0435, \u043d\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0439\u0442\u0435 \u0438 \u0442\u043e\u0447\u043d\u043e \u043d\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0439\u0442\u0435 \u0441\u0432\u043e\u0438\u0445 \u0418\u0418-\u0430\u0433\u0435\u043d\u0442\u043e\u0432. \u041e\u0441\u0432\u043e\u0439\u0442\u0435 \u043f\u0440\u043e\u0441\u0442\u043e\u0439 \u0438 \u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u0440\u0435\u0436\u0438\u043c\u044b \u043f\u0440\u043e\u043c\u043f\u0442\u043e\u0432.",
        triggers: "\u041d\u0430\u0441\u0442\u0440\u043e\u0439\u0442\u0435, \u043a\u043e\u0433\u0434\u0430 \u0438 \u043a\u0430\u043a \u0437\u0430\u043f\u0443\u0441\u043a\u0430\u044e\u0442\u0441\u044f \u0432\u0430\u0448\u0438 \u0430\u0433\u0435\u043d\u0442\u044b \u2014 \u0440\u0430\u0441\u043f\u0438\u0441\u0430\u043d\u0438\u044f, \u0432\u0435\u0431\u0445\u0443\u043a\u0438, \u043e\u0442\u0441\u043b\u0435\u0436\u0438\u0432\u0430\u043d\u0438\u0435 \u0444\u0430\u0439\u043b\u043e\u0432 \u0438 \u043c\u043d\u043e\u0433\u043e\u0435 \u0434\u0440\u0443\u0433\u043e\u0435.",
        pipelines: "\u0421\u043e\u0435\u0434\u0438\u043d\u044f\u0439\u0442\u0435 \u0430\u0433\u0435\u043d\u0442\u043e\u0432 \u0432 \u0432\u0438\u0437\u0443\u0430\u043b\u044c\u043d\u044b\u0435 \u043a\u043e\u043d\u0432\u0435\u0439\u0435\u0440\u044b. \u0421\u0442\u0440\u043e\u0439\u0442\u0435 \u043c\u043d\u043e\u0433\u043e\u0430\u0433\u0435\u043d\u0442\u043d\u044b\u0435 \u0440\u0430\u0431\u043e\u0447\u0438\u0435 \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u044b \u043d\u0430 \u043a\u043e\u043c\u0430\u043d\u0434\u043d\u043e\u043c \u0445\u043e\u043b\u0441\u0442\u0435.",
